using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): probe without throwing ---

// 2a. Type that IS resolvable (default reflection resolver handles it)
if (options.TryGetTypeInfo<Person>(out var info))
    Console.WriteLine($"TryGetTypeInfo<Person> → found ({info!.Type.Name})");
else
    Console.WriteLine("TryGetTypeInfo<Person> → not available");

// 2b. Type that is NOT resolvable (empty resolver knows no types)
var restricted = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
        .WithAddedModifier(ti =>
        {
            // Strip every type so nothing resolves
            if (ti.Type != typeof(void))
                ti.Properties.Clear();
        })
};
// Use a resolver that literally returns null for everything:
restricted = new JsonSerializerOptions { TypeInfoResolver = JsonTypeInfoResolver.Combine() };

if (restricted.TryGetTypeInfo<Person>(out var missing))
    Console.WriteLine($"TryGetTypeInfo<Person> on empty resolver → found");
else
    Console.WriteLine("TryGetTypeInfo<Person> on empty resolver → not available (no exception!)");

// --- done ---
public record Person(string Name, int Age);

